(801, '_transient_jm_promote-jobs-template_ru_RU', '\n				<style>\n					.promote-job-modal {\n						display: flex;\n						gap: 40px;\n						width: 820px;\n						max-width: 70vw;\n						padding: 30px 80px 50px 80px;\n					}\n					.promote-job-modal-column-left,\n					.promote-job-modal-column-right {\n						flex: 1;\n					}\n					img.promote-jobs-image {\n						display: block;\n						width: 100%;\n					}\n					h2.promote-jobs-heading {\n						font-size: 39px;\n						font-weight: 400;\n						line-height: 105%;\n						margin: 0 0 24px;\n					}\n					.promote-job-modal-column-left {\n						display: flex;\n						justify-content: space-between;\n						flex-direction: column;\n					}\n					.promote-list {\n						margin: 0 0 24px;\n						padding: 0;\n						list-style: none;\n					}\n					li.promote-list-item {\n						background: url(\"data:image/svg+xml,<svg width=\\\"24\\\" height=\\\"24\\\" viewBox=\\\"0 0 24 24\\\" fill=\\\"none\\\" xmlns=\\\"http://www.w3.org/2000/svg\\\"><mask id=\\\"mask0_20018663_2259\\\" style=\\\"mask-type:luminance\\\" maskUnits=\\\"userSpaceOnUse\\\" x=\\\"3\\\" y=\\\"5\\\" width=\\\"18\\\" height=\\\"14\\\"><path d=\\\"M8.75685 15.9L4.57746 11.7L3.18433 13.1L8.75685 18.7L20.698 6.69999L19.3049 5.29999L8.75685 15.9Z\\\" fill=\\\"white\\\"/></mask><g mask=\\\"url%28%23mask0_20018663_2259%29\\\"><rect width=\\\"23.8823\\\" height=\\\"24\\\" fill=\\\"%232270B1\\\"/></g></svg>\") no-repeat 0 -3px;\n						font-size: 14px;\n						list-style: none;\n						padding-left: 32px;\n						margin: 12px 0;\n					}\n					.promote-buttons-group .button {\n						padding: 10px 16px;\n						border-radius: 2px;\n						margin-right: 18px;\n						border: 0;\n					}\n					.promote-buttons-group .button-primary {\n						background: #2270b1;\n						color: #fff;\n					}\n					.promote-buttons-group .button-secondary {\n						background: #fff;\n						color: #2270B1;\n						border: 1px solid #2270B1;\n					}\n					@media screen and (max-width: 1000px) {\n						.promote-job-modal-column-right {\n							display: none;\n						}\n					}\n					@media screen and (max-width: 782px) {\n						.promote-job-modal {\n							padding: 0px 25px 25px;\n						}\n					}\n				</style>\n				<div class=\"promote-job-modal\">\n					<div class=\"promote-job-modal-column-left\">\n						<div class=\"promote-job-modal-features\">\n							<h2 class=\"promote-jobs-heading\">\n								Promote your job on our partner network\n							</h2>\n\n							<ul class=\"promote-list\">\n								<li class=\"promote-list-item\">Post jobs to over 25,000 job sites</li>\n								<li class=\"promote-list-item\">Powered by JobTarget.com</li>\n							</ul>\n						</div>\n\n						<slot name=\"buttons\" class=\"promote-buttons-group\">\n							An error occured loading the promote feature.\n							<a class=\"promote-button button button-secondary\" target=\"_blank\" rel=\"noopener noreferrer\" href=\"https://wpjobmanager.com/jobtarget?utm_source=plugin_wpjm&utm_medium=promote-dialog&utm_campaign=promoted-jobs\">Learn More</a>\n						</slot>\n					</div>\n					<div class=\"promote-job-modal-column-right\">\n						<img class=\"promote-jobs-image\" src=\"https://wpjobmanager.com/wp-content/uploads/2023/07/promoted-jobs-right.png\" alt=\"Reach thousands of potential applicants with one job post.\" />\n					</div>\n				</div>\n			', 'off'),
