(222, 1, '2026-02-02 08:09:32', '2026-02-02 04:09:32', '<div class=\"vacancy-section vacancy-section_magritte\">\r\n<div class=\"g-user-content\" data-qa=\"vacancy-description\">\r\n\r\n<strong>Обязанности</strong>:\r\n<ul>\r\n 	<li>Консультирование клиентов по вопросам ведения бухгалтерского учета и отчетности в программе 1С:БГУ и 1С: ЗКГУ 8 на рабочем месте заказчика, на рабочем месте исполнителя или дистанционно из офиса.</li>\r\n 	<li>Выявление и исправление ошибок пользователей</li>\r\n 	<li>Обучение пользователей работе в программе</li>\r\n 	<li>Помощь в подготовке отчетности</li>\r\n</ul>\r\n<strong>Требования</strong>:\r\n<ul>\r\n 	<li>Знание бухгалтерского (бюджетного), налогового, учета, расчета заработной платы</li>\r\n 	<li>Умение выстраивать коммуникации с коллегами и клиентами.</li>\r\n 	<li>Опыт работы бухгалтером в государственном учреждении и/или Опыт работы в организациях франчайзи 1С не менее трех лет.</li>\r\n 	<li>Владение конфигурацией 1С:ЗКГУ и/или 1С:БГУ</li>\r\n 	<li>Личные качества: коммуникабельность, дисциплинированность, ответственность, стрессоустойчивость, готовность обучаться и обучать, желание развиваться в профессиональной сфере</li>\r\n</ul>\r\n<strong>Условия</strong>:\r\n<ul>\r\n 	<li>Оформление в соответствии ТК РФ</li>\r\n 	<li>Постоянная работа, полный рабочий день</li>\r\n 	<li>Консультирование удаленно, по телефону/или с выездом к Заказчику.</li>\r\n 	<li>Сертификация за счет компании.</li>\r\n 	<li>Карьерный, профессиональный и личностный рост</li>\r\n 	<li>Оформление, отпуск, больничный и пр. по ТК</li>\r\n 	<li>График работы: 5/2, с 9:00 до 18:00</li>\r\n 	<li>М. Волгоградский проспект</li>\r\n</ul>\r\n</div>\r\n</div>', 'Консультант 1С по бюджетному учету', '', 'publish', 'closed', 'closed', '', '%d0%ba%d0%be%d0%bd%d1%81%d1%83%d0%bb%d1%8c%d1%82%d0%b0%d0%bd%d1%82-1%d1%81-%d0%bf%d0%be-%d0%b1%d1%8e%d0%b4%d0%b6%d0%b5%d1%82%d0%bd%d0%be%d0%bc%d1%83-%d1%83%d1%87%d0%b5%d1%82%d1%83', '', '', '2026-02-02 08:10:13', '2026-02-02 04:10:13', '', 0, 'http://127.0.0.1:8000/?post_type=vacancy&#038;p=222', 0, 'vacancy', '', 0);
